 func TestConfirmUpdate_InteractiveGate(t *testing.T) {
 	requireGit(t)
 	canonical, _, head := makeUpdateRepo(t)
 	newSHA := commitFile(t, canonical, "rules/more.md", "More.\n", "add more rules")

