 	cmd.SetOut(&out)
 	cmd.SetIn(strings.NewReader("y\n"))
 	rc := &runtimeContext{Access: Access{NonInteractive: false}}

 	ok, err := confirmUpdate(cmd, rc, m, head, res, true, updateFlags{})
 	if err != nil {
 		t.Fatalf("confirmUpdate: %v", err)
